module ip_checksum(  
    input [79:0] data, // 5 x 16-bit data  
    output reg [15:0] checksum  
);  
    integer i;  
    reg [31:0] obf_sum;  

    always @(*) begin  
        obf_sum = 0;  
        for (i = 0; i < 5; i = i + 1) begin  
            obf_sum = obf_sum + data[16*i +: 16];  
        end  
        // Add carry  
        obf_sum = (obf_sum >> 16) + (obf_sum & 16'hFFFF);  
        // One's complement  
        checksum = ~obf_sum[15:0];  
    end  
endmodule
